-                apply_style(cell, style);
+                if let Some(fg) = fg {
+                    cell.fg = fg;
+                }
+                if let Some(bg) = bg {
+                    match bg.a() {
+                        0 => {} // Fully transparent: no-op
+                        255 => cell.bg = bg,
+                        _ => cell.bg = bg.over(cell.bg),
+                    }
+                }
+                if let Some(attrs) = attrs {
+                    let cell_flags: ftui_render::cell::StyleFlags = attrs.into();
+                    cell.attrs = cell.attrs.with_flags(cell_flags);
+                }
             }
